def solid(width: int, height: int, red: int, green: int, blue: int) -> Raster:
    data = bytearray(width * height * 3)
    for index in range(0, len(data), 3):
        data[index] = red
        data[index + 1] = green
        data[index + 2] = blue
    return Raster(width, height, 3, data)

