def diagonal_gradient(width: int, height: int) -> Raster:
    data = bytearray(width * height * 3)
    denominator = max(1, width + height - 2)
    for row in range(height):
        for col in range(width):
            index = (row * width + col) * 3
            blend = ((col + row) * 255) // denominator
            data[index] = blend
            data[index + 1] = (col * 255) // max(1, width - 1)
            data[index + 2] = (row * 255) // max(1, height - 1)
    return Raster(width, height, 3, data)

