def radial_gradient(width: int, height: int) -> Raster:
    data = bytearray(width * height * 3)
    center_x = (width - 1) / 2
    center_y = (height - 1) / 2
    max_distance = math.hypot(center_x, center_y) or 1.0
    for row in range(height):
        for col in range(width):
            distance = math.hypot(col - center_x, row - center_y)
            value = int(min(255, (distance / max_distance) * 255))
            index = (row * width + col) * 3
            data[index : index + 3] = bytes((value, 255 - value, value // 2))
    return Raster(width, height, 3, data)

