def checkerboard(width: int, height: int, cell: int = 8) -> Raster:
    data = bytearray(width * height * 3)
    for row in range(height):
        for col in range(width):
            light = ((row // cell) + (col // cell)) % 2 == 0
            value = 220 if light else 25
            index = (row * width + col) * 3
            data[index : index + 3] = bytes((value, value, value))
    return Raster(width, height, 3, data)

