def sine_stripes(width: int, height: int, frequency: float = 4.0) -> Raster:
    data = bytearray(width * height * 3)
    for row in range(height):
        for col in range(width):
            wave = (math.sin((col / max(1, width - 1)) * math.pi * 2 * frequency) + 1) * 0.5
            value = int(wave * 255)
            index = (row * width + col) * 3
            data[index : index + 3] = bytes((value, 80, 255 - value))
    return Raster(width, height, 3, data)

