def bordered_frame(width: int, height: int, border: int = 4) -> Raster:
    data = bytearray(width * height * 3)
    for row in range(height):
        for col in range(width):
            on_border = (
                row < border
                or col < border
                or row >= height - border
                or col >= width - border
            )
            index = (row * width + col) * 3
            if on_border:
                data[index : index + 3] = b"\xff\x40\x40"
            else:
                data[index : index + 3] = b"\x20\x60\xa0"
    return Raster(width, height, 3, data)

