def noise(width: int, height: int, seed: int = 7) -> Raster:
    rng = random.Random(seed)
    data = bytearray(width * height * 3)
    for index in range(0, len(data), 3):
        data[index] = rng.randint(0, 255)
        data[index + 1] = rng.randint(0, 255)
        data[index + 2] = rng.randint(0, 255)
    return Raster(width, height, 3, data)

