def high_contrast_patch(width: int, height: int) -> Raster:
    data = bytearray(width * height * 3)
    for row in range(height):
        for col in range(width):
            dark = (row + col) % 2 == 0
            index = (row * width + col) * 3
            if dark:
                data[index : index + 3] = b"\x10\x10\x10"
            else:
                data[index : index + 3] = b"\xf0\xf0\xf0"
    return Raster(width, height, 3, data)

